object.PropertiesDefinition:
[
    {
        "name": "__gptProvider",
        "title": "LLM provider",
        "hint": "E.g., AzureOpenAI. If left empty, the default provider from the Bot persona Component will be used.",
        "controlSettings": {
            "controlType": "dropdown",
            "defaultValue": "default",
            "dataType": "string",
            "options": [
                "default",
                "AzureOpenAI",
                "OpenAI",
                "Gemini",
                "Claude"
            ]
        }
    },
    {
        "name": "__gptModel",
        "title": "LLM model",
        "hint": "E.g., gpt-4.1-mini. If left empty, the default model from the Bot persona Component will be used.",
        "controlSettings": {
            "controlType": "dropdown",
            "defaultValue": "default",
            "dataType": "string",
            "options": [
                "default",
                "gpt-4o",
                "gpt-4o-mini",
                "gpt-4.1",
                "gpt-4.1-mini",
                "gpt-4.1-nano",
                "gemini-2.5-flash",
                "gemini-2.5-flash-lite",
                "claude-sonnet-4-5",
                "claude-haiku-4-5"
            ]
        }
    },
    {
        "name": "__gptServiceHost",
        "title": "LLM service host",
        "hint": "LLM service endpoint URL, e.g., vocallsopenaise.openai.azure.com. If left empty, the default host from the Bot persona Component will be used; if that is empty too, the host from the module configuration will be used.",
        "defaultValue": "",
        "controlSettings": {
            "controlType": "text",
            "maxLength": 1000,
            "dataType": "string",
            "readonly": false
        }
    },
    {
        "name": "__temperature",
        "title": "Temperature",
        "hint": "Determines the randomness of responses, corresponding to the perceived creativity of the output. Higher values make responses more random and creative, while lower values make them more focused and deterministic. Acceptable values are between 0.0 and 1.0. Default is 0.0. For standard use, the recommended maximum is 0.3. Use a decimal point.",
        "multiLanguage": false,
        "controlSettings": {
            "defaultValue": "0",
            "controlType": "text",
            "maxLength": 100,
            "dataType": "string",
            "readonly": false
        }
    },
    {
        "name": "__recognitionNodeDefaultMinTimeout",
        "title": "Min speech timeout",
        "hint": "The amount of time the voicebot waits before the client starts speaking (in ms)",
        "multiLanguage": false,
        "controlSettings": {
            "defaultValue": "8000",
            "controlType": "text",
            "maxLength": 100,
            "dataType": "string",
            "readonly": false
        }
    },
    {
        "name": "__recognitionNodeDefaultMaxTimeout",
        "title": "Max speech timeout",
        "hint": "The maximum amount of time the voicebot will wait while the client is speaking (in ms)",
        "multiLanguage": false,
        "controlSettings": {
            "defaultValue": "30000",
            "controlType": "text",
            "maxLength": 100,
            "dataType": "string",
            "readonly": false
        }
    },    
    {
        "name": "__silenceWindow",
        "title": "Silence window",
        "hint": "Time interval after speech is recognized by STT during which the system waits to confirm the user has finished speaking before sending the transcript to the LLM. Previously called 'Reaction type’ – ‘Custom reaction interval' in the STT element. Default is 1300 ms. Lower values make the bot respond faster but increase the chance of interruptions if the user continues speaking. Higher values give the user more time but may make the bot seem too slow.",
        "multiLanguage": false,
        "controlSettings": {
            "defaultValue": "1300",
            "controlType": "text",
            "maxLength": 100,
            "dataType": "string",
            "readonly": false
        }
    },
    {
        "name": "__dialogControlOnEntry",
        "title": "Dialog control on entry",
        "hint": "Specifies how the Dialog node behaves on entry. Defaults to auto-detection, which decides whether the bot speaks (and uses a message or not) or waits for the user based on predefined rules (see OmniAgent Academy). This setting can override the default behavior.",
        "controlSettings": {
            "controlType": "dropdown",
            "defaultValue": "default",
            "dataType": "string",
            "options": [
                "default",
                "userFirst",
                "botFirst"
            ]
        }
    },
    {
        "name": "__usePersonaAndKB",
        "title": "Use Bot persona and KB",
        "hint": "If true, the bot uses all settings from the Bot persona and Knowledge base Components to generate the message. Only disable this if the LLM fails to generate the message as expected, or responds with something like: 'Sorry, I cannot do this.'",
        "controlSettings": {
            "controlType": "dropdown",
            "defaultValue": "true",
            "options": [
                "true",
                "false"
            ]
        }
    },    
    {
        "name": "__intentClassifierMode",
        "title": "Intent classifier mode",
        "hint": "If true, all intents are included in the LLM prompt. Useful when the Dialog node handles categorizing of requests. See the Smart Routing chapter in OmniAgent Academy.",
        "controlSettings": {
            "controlType": "dropdown",
            "defaultValue": "false",
            "options": [
                "true",
                "false"
            ]
        } 
    },
    {
        "name": "__objective",
        "title": "Objective",
        "hint": "The goal to be achieved by the dialogue. Can be a verbal description or a list of steps. For example: Find out what the customer needs. For longer or more complex objectives, see OmniAgent Academy for examples and ideally format prompts in Markdown.",
        "controlSettings": {
            "controlType": "text",
            "maxLength": 25000,
            "dataType": "string",
            "rows": 5,
            "readonly": false
        }
    },
    {
        "name": "__message",
        "title": "Message prompt",
        "hint": "Instructions for generating a message the bot should say when entering the Dialog node. For example: Greet the client and ask how you can help. This message is only generated the first time the Dialog node is entered. Afterwards, the bot follows the previous dialogue according to its Objective. The message is skipped if the node was preceded by an action call (trigger function) from a previous node with no following message in the bot/human conversation.",
        "controlSettings": {
            "controlType": "text",
            "maxLength": 1000,
            "dataType": "string",
            "rows": 2,
            "readonly": false
        }
    },
    {
        "name": "__hints",
        "title": "Boost phrases",
        "hint": "Keywords or phrases that improve speech recognition accuracy. Use this for short phrases, less familiar words like product names that may be misrecognized, or words describing the topic at hand (e.g., 'debt' in a debt collection flow). Separate items with a comma.",
        "controlSettings": {
            "controlType": "text",
            "maxLength": 9999,
            "dataType": "string",
            "rows": 1,
            "readonly": false
        }
    }
]

