object.Code:
if (typeof __persona === 'undefined' || __persona === null) {

    // persona NOT exists
    var _errMessage = 'Use "Bot persona" component for initialization of the bot first!';
    log_error(_errMessage);
    throw _errMessage;
    return;
}

if (typeof __gptMaxTokens === "undefined") {
    var _errMessage = 'Please update component "Bot persona"!';
    log_error(_errMessage);
    throw _errMessage;
    return;
}


// check if we are chat or voice bot 
__conversationType = 'chatbot';
__conversationLanguage = context.language.substr(0, 2);

try {
    if (context.callInfo.from) {
        __conversationType = 'voicebot';
    }
} catch (e) {

}


/* default model, provider and host overide */
if (!__gptProvider || __gptProvider == 'default') __gptProvider = __defaultLLMProvider;
if (!__gptModel || __gptModel == 'default') __gptModel = __defaultModel;
if (!__gptServiceHost || __gptServiceHost == 'default') __gptServiceHost = __defaultServiceHost;

if (!__gptServiceHost || __gptServiceHost == 'default') {
    switch (__gptProvider) {
        case "AzureOpenAI": { __gptServiceHost = null; break; }
        case "OpenAI": { __gptServiceHost = "openai"; break; }
        case "Gemini": { __gptServiceHost = "gemini"; break; }
        case "Claude": { __gptServiceHost = "claude"; break; }
    }
}
if (!__gptServiceHost) __gptServiceHost = null;


if (typeof __logPrompt === 'undefined') {
    __logPrompt = false;
} else {
    if (__logPrompt == 'true' || __logPrompt === true) {
        __logPrompt = true;
    } else {
        __logPrompt = false;
    }
}


__currentComponentId = context.currentNode.id;
if (context.currentNode.id.indexOf('-') >= 0) {
    __currentComponentId = context.currentNode.id.substr(0, context.currentNode.id.lastIndexOf('-'));
}

if (__logPrompt) {
    log_debug("Entering DialogNode ID " + __currentComponentId);
}

__languageShortCode = context.language.substr(0, 2);

/* init internal variables */
__gptComponentId = context.currentNode.id; // used to filter function call history only for component where fuctions were available
__lastSpeaker = __gptGetLastSpeaker();
__firstRequest = true;
__gptOutput = null;
__gptFunctionCall = null;
__gptRepeatedCall = false;
__gptNoInputCounter = 0;
__gptDialogBargeInNodeId = "1219";
__sayInstruction = [];
__confirmIntentMode = 0;
__gptNoInputMaxLoopsDefault = 5;
__byeFromClient = false;
__byeFromBot = false;
__chatEndedCounter = 0;
__now = '';
__streamRequest = null;
__resultArrived = false;
__repCounter = 0;
__speak = false;
__recognize = false;
__requestCounter = 0;
__gptIntentClassifierTimeout = false;
__gptUnfinishedInputCounter = 0;

__gptHTMLorMDused = false;
__gptIntents = [];
__gptMaxLoops = null;
__gptLoopCounter = 0;
__streamWaitCounter = 0;
__gptMaxLoopsLabel = '';
__gptNoInputLoops = __gptNoInputMaxLoopsDefault;
__gptNoInputLoopsLabel = '';
__gptOutputConfirmation = {}; // output counter - used for explicit confirmation
__gptFunctionsDefinition = [];


/* create hints */
__gptBoostPhrases = '';
if (__hints) {
    __gptBoostPhrases = __hints;
}
if (__persona.name) {
    __gptBoostPhrases += ',' + __persona.name;
}
if (__persona.companyName) {
    __gptBoostPhrases += ',' + __persona.companyName;
}
if (__logPrompt) {
    log_debug("Boost phrases: " + __gptBoostPhrases);
}


if (__conversationType == 'chatbot') {
    __recognitionNodeDefaultMinTimeout = 0;
    __recognitionNodeDefaultMaxTimeout = 0;
}

__rDfMnT = __recognitionNodeDefaultMinTimeout;
__rDfMxT = __recognitionNodeDefaultMaxTimeout;


if (!String.prototype.replaceAll) {
    String.prototype.replaceAll = function (str, newStr) {

        // If a regex pattern 
        if (Object.prototype.toString.call(str).toLowerCase() === '[object regexp]') {
            return this.replace(str, newStr);
        }

        // If a string 
        return this.replace(new RegExp(str, 'g'), newStr);

    };
}


global.transformFunctionName = function (text) {
    if (text == null) throw "Function name is empty!";
    text = text.trim();
    text = text.toLowerCase(); // Convert to lowercase
    text = text.replace(/["'{}]/g, '') // remove quotes and brackets
    text = text.replace(/[^a-z0-9]/g, '_'); // Replace all non-alphanumeric characters with underscores
    text = text.replace(/_+/g, '_'); // Replace multiple underscores in a row with a single underscore
    return text;
}

__gptConvertDataType = function (dataType) {
    if (dataType) {
        switch (dataType) {
            case "text": return "string";
            case "number": return "number";
            case "phone": return "string";
            case "address": return "string";
            case "date": return "string";
            case "ordinal": return "integer";
            case "cardinal": return "integer";
            case "integer": return "integer";
        }
        return "string";
    } else {
        return "string";
    }
}

/* init actions */
__gptIntentClassifierChoices = "When you understand the intent (category), trigger function \"submit_intent\" with the correct ID of the users intention.\nHere is the list of all possible intents (categories) and their descriptions:\n[\n";

for (var i = 0; i < __componentOutputRelationConfig.length; i++) {

    /*log_debug('procesing intent: '+__componentOutputRelationConfig[i].Name);*/

    if (__componentOutputRelationConfig[i].SubType == 'noInput') {
        __gptNoInputLoops = parseInt(__componentOutputRelationConfig[i].MaxLoops);
        __gptNoInputLoopsLabel = __componentOutputRelationConfig[i].label;
        if (isNaN(__gptNoInputLoops)) {
            __gptNoInputLoops = __gptNoInputMaxLoopsDefault;
        }
    }

    if (__componentOutputRelationConfig[i].SubType == 'maxLoops') {
        __gptMaxLoops = parseInt(__componentOutputRelationConfig[i].MaxLoops);
        __gptMaxLoopsLabel = __componentOutputRelationConfig[i].label;
        if (isNaN(__gptMaxLoops)) {
            __gptMaxLoops = null;
        }
    }

    if (__componentOutputRelationConfig[i].SubType == 'dynamicOutput' ||
        __componentOutputRelationConfig[i].SubType == 'entityExtractionOutput') {

        try {
            if (__componentOutputRelationConfig[i].ApplyWhen == false) {
                continue; // skip intent
            }
        } catch {
            log_warn('ApplyWhen on intent ' + __componentOutputRelationConfig[i].Name + ' is invalid!');
        }

        __gptOutputConfirmation[__componentOutputRelationConfig[i].Name] = 0; // output counter - used for explicit confirmation

        var gptIntentTmp = {
            "name": transformFunctionName(__componentOutputRelationConfig[i].Name),
            "description": /*"Call this function when: " +*/ __componentOutputRelationConfig[i].Description
        };

        // append intents to global llm prompt
        if (__intentClassifierMode == true && __componentOutputRelationConfig[i].SubType == 'dynamicOutput') {
            __gptIntentClassifierChoices += "\t{\n\t\t\"id\": \"" + __componentOutputRelationConfig[i].Name + "\",\n\t\t\"description\": \"" + __componentOutputRelationConfig[i].Description + "\"\n\t},\n";

            // intent validation
            if (!__componentOutputRelationConfig[i].Description) log_warn("Missing description in intent " + __componentOutputRelationConfig[i].Name);
            if (__componentOutputRelationConfig[i].Confirmation != 'None') log_warn("In Intent classifier mode all confirmations must be disabled. Set Confirmation to None on intent " + __componentOutputRelationConfig[i].Name);
        }

        if (__componentOutputRelationConfig[i].SubType == 'entityExtractionOutput') {

            gptIntentTmp.parameters = {
                "type": "object",
                "properties": {
                },
                "required": [],
                "additionalProperties": false
            }

            var requiredAttributes = [];

            // backward compatibility with LLM bot v1 where was single entity
            if (__componentOutputRelationConfig[i].EntityName) {
                gptIntentTmp.parameters.properties[__componentOutputRelationConfig[i].EntityName] = {
                    "type": __gptConvertDataType(__componentOutputRelationConfig[i].EntityType),
                    "description": __componentOutputRelationConfig[i].EntityDescription
                }
                if (__componentOutputRelationConfig[i].EntityRequired == true) {
                    requiredAttributes.push(__componentOutputRelationConfig[i].EntityName);
                }
            } else if (__componentOutputRelationConfig[i].Entities) {
                // Parse "Entities" object
                var __entities = null;
                try {
                    __entities = JSON.parse(__componentOutputRelationConfig[i].Entities);

                    for (var j = 0; j < __entities.length; j++) {
                        var __entity = __entities[j];

                        if (__entity.Name) {

                            var __descText = __entity.Description; // default description is always fallback

                            if (context.settings
                                && context.settings.languageKey
                                && __entity["Description_" + context.settings.languageKey]) {
                                __descText = __entity["Description_" + context.settings.languageKey];
                            }

                            if (!__descText) {
                                log_warn("Missing description for entity " + __entity.Name + " in action " + __componentOutputRelationConfig[i].Name);
                            }

                            gptIntentTmp.parameters.properties[__entity.Name] = {
                                "type": __gptConvertDataType(__entity.Type),
                                "description": __descText
                            }
                            if (__entity.Required == "true" || __entity.Required === true) {
                                requiredAttributes.push(__entity.Name);
                            }
                        }
                    }

                } catch (err) {
                    var _errMessage = 'Error when parsing entities! Action: ' + __componentOutputRelationConfig[i].Name + ', entities: ' + __componentOutputRelationConfig[i].Entities + ', Error: ' + err;
                    log_error(_errMessage);
                    throw _errMessage;
                    return;
                }
            } else {
                // action has no entities
            }

            /*// slot 1
            if (__componentOutputRelationConfig[i].Slot1_Name) {
                gptIntentTmp.parameters.properties[__componentOutputRelationConfig[i].Slot1_Name] = {
                    "type": __gptConvertDataType(__componentOutputRelationConfig[i].Slot1_Type),
                    "description": __componentOutputRelationConfig[i].Slot1_Description
                }
                if (__componentOutputRelationConfig[i].Slot1_Required == 'true') {
                    requiredAttributes.push(__componentOutputRelationConfig[i].Slot1_Name);
                }
            }

            // slot 2
            if (__componentOutputRelationConfig[i].Slot2_Name) {
                gptIntentTmp.parameters.properties[__componentOutputRelationConfig[i].Slot2_Name] = {
                    "type": __gptConvertDataType(__componentOutputRelationConfig[i].Slot2_Type),
                    "description": __componentOutputRelationConfig[i].Slot2_Description
                }
                if (__componentOutputRelationConfig[i].Slot2_Required == 'true') {
                    requiredAttributes.push(__componentOutputRelationConfig[i].Slot2_Name);
                }
            }

            // slot 3
            if (__componentOutputRelationConfig[i].Slot3_Name) {
                gptIntentTmp.parameters.properties[__componentOutputRelationConfig[i].Slot3_Name] = {
                    "type": __gptConvertDataType(__componentOutputRelationConfig[i].Slot3_Type),
                    "description": __componentOutputRelationConfig[i].Slot3_Description
                }
                if (__componentOutputRelationConfig[i].Slot3_Required == 'true') {
                    requiredAttributes.push(__componentOutputRelationConfig[i].Slot3_Name);
                }
            }

            // slot 4
            if (__componentOutputRelationConfig[i].Slot4_Name) {
                gptIntentTmp.parameters.properties[__componentOutputRelationConfig[i].Slot4_Name] = {
                    "type": __gptConvertDataType(__componentOutputRelationConfig[i].Slot4_Type),
                    "description": __componentOutputRelationConfig[i].Slot4_Description
                }
                if (__componentOutputRelationConfig[i].Slot4_Required == 'true') {
                    requiredAttributes.push(__componentOutputRelationConfig[i].Slot4_Name);
                }
            }


            // slot 5
            if (__componentOutputRelationConfig[i].Slot5_Name) {
                gptIntentTmp.parameters.properties[__componentOutputRelationConfig[i].Slot5_Name] = {
                    "type": __gptConvertDataType(__componentOutputRelationConfig[i].Slot5_Type),
                    "description": __componentOutputRelationConfig[i].Slot5_Description
                }
                if (__componentOutputRelationConfig[i].Slot5_Required == 'true') {
                    requiredAttributes.push(__componentOutputRelationConfig[i].Slot5_Name);
                }
            }*/

            gptIntentTmp.parameters.required = requiredAttributes;

            /*log_debug("function set properly!");
            log_debug(JSON.stringify(gptIntentTmp));*/
        }

        // TODO: maybe enable turn on and off in Properties?
        if (__componentOutputRelationConfig[i].SubType == 'entityExtractionOutput') {
            //log_debug(JSON.stringify(gptIntentTmp));
            __gptIntents.push(gptIntentTmp);
        }
    }
}

// repeated call detection
if (!global.hasOwnProperty("__gpt_enteredNodes"))
    __gpt_enteredNodes = [];

var idParts = context.currentNode.id.split("-");

if (!!idParts && idParts.length) {
    /*var thisNodeId = idParts[0]; -- bug found in: https://vocalls.atlassian.net/browse/CS-1113 */
    var thisNodeId = idParts.length > 1
        ? idParts[idParts.length - 2]  // DialogNode is in a Tab
        : idParts[0];                  // DialogNode is in default Tab


    if (__gpt_enteredNodes.includes(thisNodeId))
        __gptRepeatedCall = true;
    else
        __gpt_enteredNodes.push(thisNodeId);
}


__gptIntentClassifierChoices += "]\n\nYou can also trigger another tool/functions when customer will ask for something else.";

//log_debug(__gptIntentClassifierChoices);

// add hardcoded intents
if (__intentClassifierMode == true) {
    __gptIntents.push({
        "name": "submit_intent",
        "description": "Submit the intent of the user.",
        "parameters": {
            "type": "object",
            "properties": {
                "intent_id": {
                    "type": "string",
                    "description": "ID of the intent"
                }
            },
            "required": ["intent_id"]
        }
    });
}

