    "name": "user_wants_to_wait",
    "description": "The user asked the assistant to wait a moment",
    "parameters": {
        "type": "object",
        "properties": {
            "implicit": {
                "type": "boolean",
                "description": "Set to true unless the user has explicitly asked the assistant to wait. Otherwise false"
            }
