/**
 * Returns current node prefix
 * @return {string} prefix
 */
__gptDialog_getNodePrefix = function () {
    var separator = "-";
    var currentId = context.currentNode.id.split(separator);

    return currentId.length > 1
        ? currentId.slice(0, -1).join(separator) + separator
        : "";
};

/**
 * Makes a local goto destination nodeId including prefix
 * @param {string} nodeId
 * @return {string} full nodeId
 */
__gptDialog_makeLocalNodeId = function (nodeId) {
    if (global.hasOwnProperty("__gptDialogComponentIdPrefix") && __gptDialogComponentIdPrefix != null)
        return __gptDialogComponentIdPrefix + nodeId;

    if (!context.currentNode.id)
        return nodeId;

    var separator = "-";
    var output = context.currentNode.id.split(separator);

    output[output.length - 1] = nodeId;
    return output.join(separator);
};

__gptDialogComponentIdPrefix = __gptDialog_getNodePrefix();
__gptDialogVADEnabled = __persona.allowBargeIn;
__gptSkipVAD = false;

__gptDialog_onVoiceDetected = function () {
    var destination = __gptDialog_makeLocalNodeId(__gptDialogBargeInNodeId);

    if (__logPrompt)
        log_debug("VAD detected! Processing in node ID: " + destination);

    goto(destination); /* because of concurrent JS execution !! */
    stopVoiceDetection();
    stopPlayingAudio();
}

__gptDialog_getSimplifiedHistory = function (maxRows = null) {
    var msgHistory = '';
    var prevMsgs = __gptDialog_getPrevMessages();
    var _fromPos = 0;

    if (maxRows != null && prevMsgs.length > maxRows) {
        _fromPos = prevMsgs.length - maxRows;
    }

    for (var i = _fromPos; i < prevMsgs.length; i++) {
        if (prevMsgs[i].role == 'assistant' && prevMsgs[i].content) {
            msgHistory += "Assistant: " + prevMsgs[i].content + "\n";
        } else if (prevMsgs[i].role == 'user') {
            msgHistory += "User: " + prevMsgs[i].content + "\n";
        }
    }
    return msgHistory;
}


__gptDialog_getSystemMessage = function (message) {
    return {
        "role": "system",
        "content": message
    }
}

getLastDialogNodeOutputName = function() {
    return __gptFunctionCall;
}

__gptInput = null;
__gptLastDialogMessage = null; // bot, user, action
__gptLastActionResult = null;
__lastMessage = null;
__lastMessages = __gptDialog_getPrevMessages();

//log_debug('History to evaluate: ' + JSON.stringify(__lastMessages));

for (var i = __lastMessages.length-1; i >= 0; i--) {
    __lastMessage = __lastMessages[i];

    if (__lastMessage['role'] == 'function') {
        __gptLastDialogMessage = 'action';
        __gptLastActionResult = __lastMessage['content'];
        break;
    } else if (__lastMessage['role'] == 'user') {
        __gptInput = __lastMessage['content'];
        __gptLastDialogMessage = 'user';
        break;
    } else if (__lastMessage['role'] == 'assistant' && __lastMessage['function_call']) {
        __gptLastDialogMessage = 'action';
        break;
    } else if (__lastMessage['role'] == 'assistant') {
        __gptLastDialogMessage = 'bot';
        break;
    }
}

//log_debug('Last dialog message: ' + __gptLastDialogMessage);

if (__message == '') {
    __message = null;
