if (__message && __message.length <= 2) {
    __message = null; // this could fix issue whem message contains two apostrohpes -> no valid GPT instruct using just two letters!
}


// validation IF ALL functions and their result are in the history!
var __functionCallCount = 0;
var __functionResultCount = 0;

for (var i = 0; i < __lastMessages.length; i++) {
    if (__lastMessages[i].function_call) __functionCallCount++;
    if (__lastMessages[i].role == "function") __functionResultCount++;
}

var __gptFunctionCallHistoryCount = 0;
for (var i = 0; i < __gptFunctionCallHistory.length; i++) {
    if (__gptFunctionCallHistory[i].componentId == __gptComponentId) {
        __gptFunctionCallHistoryCount++; // count only functions in current Dialog Node
    }
}

var __validFunctionCall = true;
if (__functionCallCount != __functionResultCount) __validFunctionCall = false;
if (__functionCallCount != __gptFunctionCallHistoryCount) __validFunctionCall = false;

if (!__validFunctionCall && __gptDialogHistoryStartFrom == 0) {
    log_warn("The number of action(functions) does not match! Action history count: " + __gptFunctionCallHistoryCount +" (total: " + __gptFunctionCallHistory.length + "), function call count: " + __functionCallCount + ", results found: " + __functionResultCount);
    log_warn(JSON.stringify(__gptFunctionCallHistory));
    log_warn(JSON.stringify(__lastMessages));
}

// evaluate if last result contains HTML or MD
if (__gptLastDialogMessage == "action" && __gptLastActionResult) {
    if (__gptIsXML(__gptLastActionResult)) {
        __gptHTMLorMDused = true;
    } else if (__gptIsMarkdown(__gptLastActionResult)) {
        __gptHTMLorMDused = true;
    }
