    // start - 15*200 ms for response
    if (typeof Task === "undefined") {
        // start - 15*200 ms for response
        __streamWaitAttempts = 15;
    }
} 

if (__streamWaitAttempts === 15 || __streamWaitAttempts === null) {
    // at first or during repeat continue
    __streamRequest.then( 
        function (result) { 
            __gptRequestEnd = new Date();
            __gptRequestTTFT = __gptRequestEnd - __gptRequestStart; // time to first token

            __streamWaitAttempts = null; // wait signal for next response
            __resultArrived = true;

            if (__logPrompt) {
                log_debug("GPT response (" + __gptRequestTTFT+"ms):" + JSON.stringify(result)); 
            }

            __streamRequest = null; 

            if (result.success) {
                __requestCounter = 0; 

                if (!result.response || result.response == "[DONE]") { 
                    __recognize = true; 

                    /* __speak is false, so we can disable VAD immediatelly */
                    if (__gptDialogVADEnabled) {
                        stopVoiceDetection();
                    }

                    return; 
                } 


                if (result.response.choices && result.response.choices.length > 0 && result.response.choices[0].message.function_call) {

                    __gptFunctionCall = result.response.choices[0].message.function_call.name;
                    __gptFunctionObject = result.response.choices[0].message.function_call;

                    return;
                }

                __streamRequest = result.next;

                if (!result.response.choices || result.response.choices.length == 0) {
                    return; 
                } 

                var message = result.response.choices[0].message; 

                if (typeof message.content === 'undefined') { 
                    message.content = null; 
                } 

                if (!!message.content) { 
                    __gptOutput = message.content; 
                    __gptInput = ""; 
                    __recognize = false; 
                    __speak = true;

                    if (__gptOutput.indexOf("```") >= 0 ||
                        __gptOutput.indexOf("`function") >= 0 ||
                        __gptOutput.indexOf("`typescript") >= 0 ||
                        (__gptOutput.indexOf("{") >= 0 && __gptOutput.indexOf("\"")) ||
                        (__gptOutput.indexOf("{") >= 0 && __gptOutput.indexOf("'")) ||
                        __gptOutput.indexOf("Calling function") >= 0) {
                            if (__logPrompt) { log_warn("GPT code output instead of function call. Output skipped. Content: " + __gptOutput); }
                            __gptOutput = ""; /* output contains code */
                    }
                }
            } else {
                __requestCounter++;  
