                        __confirmIntentMode = 1;
                    }

                    if (__componentOutputRelationConfig[i].Confirmation == 'Implicit') {
                        __confirmIntentMode = 2;
                    }

                    if (__componentOutputRelationConfig[i].Confirmation == 'Auto') {
