__gptIntentClassifier = null; 

// skip when last action was Set result (bot need to say that!)
if (__intentClassifierMode == false && __gptLastDialogMessage != 'action') {

    if (__confirmIntentMode == 0 && (__sayInstruction == null || __sayInstruction.length == 0)) { 

        var msgHistory = __gptDialog_getSimplifiedHistory(6) //pass last 6 rows from history to save some capacity; 

        var intentCount = 0; 

        var intents = "[\n"; 
        for (var i = 0; i < __componentOutputRelationConfig.length; i++) { 
            if (__componentOutputRelationConfig[i].Name 
                && __componentOutputRelationConfig[i].SubType == 'dynamicOutput' 
                && __componentOutputRelationConfig[i].ApplyWhen == true) { 
                    intentCount++; 
                    intents += "  {\n    \"id\": \"" + __componentOutputRelationConfig[i].Name + "\",\n    \"description\": \"" + __componentOutputRelationConfig[i].Description.replace(/\n/g, " ").replace(/"/g, "'") + "\"\n  },\n";
            }
        }


        intents += "  {\n    \"id\": \"user_answered_entity\",\n    \"description\": \"The user said provided an entity value that was asked by the assistant (like exact number, name, etc...).\"\n  },\n  {\n    \"id\": \"unfinished_input\",\n    \"description\": \"The user asked the assistant to wait a moment.\"\n  }\n]";

        var classifierSystemMessage = `Now you are an intent classifier. Based on the dialog history provided below, classify the user's last intent into one of the categories listed or return NULL if not classifiable. 

DIALOG HISTORY: 
`+ msgHistory+` 

LIST OF INTENTS AND THEIR DESCRIPTIONS: 
`+ intents + ` 

Include only the category ID in the response, or NULL if the user's intent cannot be assigned to any of them!
`; 


        var intentLLMModel = "gpt-4.1-nano";

        switch (__gptProvider) {
            case "Gemini": { intentLLMModel = "gemini-2.5-flash-lite"; break; }
            case "Claude": { intentLLMModel = "claude-4-5-sonnet-latest"; break; }
        }

        if (__gptModel.indexOf("gpt-5") >= 0) {
            // gpt 5 is present, lets use nano model instead of 4.1-nano
            intentLLMModel = "gpt-5-nano";
        }

        intentClassifierRequest = { 
            "model": intentLLMModel,
            "messages": [ 
                { 
                    "role": "system", 
                    "content": classifierSystemMessage 
                } 
            ], 
            "top_p": 1, 
            "service_host": __gptServiceHost, 
            "frequency_penalty": 0, 
            "presence_penalty": 0, 
            "share_connection": true 
        }
        if (__gptModel.indexOf("gpt-5") >= 0) {
            intentClassifierRequest["max_completion_tokens"] = 10;
        } else {
            intentClassifierRequest["max_tokens"] = 10;
            intentClassifierRequest["temperature"] = 0;
        }

        if (__logPrompt) { 
            log_debug('Intent classifier request: ' + JSON.stringify(intentClassifierRequest)); 
        } 

        __gptIntentClassifier = gptRequest("chat/completions", intentClassifierRequest);
    }
}

// need to clear otherwise intent classifier will be skipped all the time
__gptLastDialogMessage = null;

__gptIntentClassifierTimeout = false;
__gptDetectedIntent = null;

var __regexDigits = /\d.*\d/;
if (__gptInput && __regexDigits.test(__gptInput)) {
    __gptDetectedIntent = "user_answered_entity"; // more than one digit is present, always play keyboard sound
}

if (__gptIntentClassifier == null) return; 

function handleIntentClassifierResponse(result) {

    __gptRequest2End = new Date();
    __gptRequest2Duration = __gptRequest2End - __gptRequest2Start;

    if (__gptRequest2Duration > 250) { // normal behavior is 1ms - because it must be evaluted much earlier!
        if (__logPrompt) {
            log_warn("Intent classification delay: +" + __gptRequest2Duration + "ms!");
        }
    }

    __gptIntentClassifier = null; /* prevent repeated evaluation during fragmented speech */
    if (!result || !result.response || !Array.isArray(result.response.choices) || result.response.choices.length == 0) {
        log_error('Intent classification failed: ' + JSON.stringify(result));
    } else {
        if (result.response &&
            result.response.choices &&
            result.response.choices.length > 0 &&
            result.response.choices[0].message &&
            result.response.choices[0].message.content) {
            var gptDetectedIntent = result.response.choices[0].message.content;
            __gptDetectedIntent = transformFunctionName(gptDetectedIntent);

            if (__logPrompt) {
                log_debug('Classifier output: ' + gptDetectedIntent);
                log_debug('Detected function: ' + __gptFunctionCall);
            }
            /* check if this function already exists */

            for (var i = 0; i < __componentOutputRelationConfig.length; i++) {
                if (__componentOutputRelationConfig[i].Name) {
                    if (transformFunctionName(__componentOutputRelationConfig[i].Name) == transformFunctionName(gptDetectedIntent)) {
                        /* this condition will solve situation, where LLM itself correcly detected the correct function */
                        if (__gptFunctionCall != __componentOutputRelationConfig[i].Name) {
                            __gptFunctionCall = __componentOutputRelationConfig[i].Name;
                            __gptFunctionObject = {
                                "name": __gptFunctionCall,
                                "arguments": "{}" /*JSON.stringify(__functionArgsGuess)*/
                            };
                            // function call injected successfully 
                            if (__logPrompt) {
                                log_debug('Function injection successfull!');
                                log_debug('Detected function: ' + __gptFunctionCall);
                            }
                        } else {
                            if (__logPrompt) {
                                log_debug('Both classifiers guess is correct!');
                            }
                        }
                        break;
                    }
                }
            }
        }
    } 
} 


__gptRequest2Start = new Date();


if (typeof Task !== "undefined") {

    return Task.timeout(500, __gptIntentClassifier, "timeout").then(result => {
        if (result == "timeout") {
            // timeout!
            if (__logPrompt) {
                log_warn("Intent classification timeout!");
            }
            __gptIntentClassifierTimeout = true;
        } else {
            handleIntentClassifierResponse(result);
        }
    });

} else {
    // backward compatibility
    return __gptIntentClassifier.then(handleIntentClassifierResponse);
}

__gptRequestStart = new Date();
__streamWaitAttempts = null;
__streamRequest = null;
__gptCurrentWaitDelay = null;
__requestCounter = 0;
__typingSoundPlayed = false;

__gptCurrentMessages = ([ 
    { 
        "role": "system", 
        "content": __gptDialog_description() 
    } 
]).concat(__exampleMessages, __gptDialog_getPrevMessages(), __sayInstruction); 
__gptCurrentModel = __gptModel; // main model for dialog  like gpt4o 


if (__intentClassifierMode == true) {
    // append instructions when we are in intent classifier mode
    __gptCurrentMessages[0].content += "\n\n" + __gptIntentClassifierChoices;
}


if (__confirmIntentMode == 1) { 
    // generate confirmation 

    __gptCurrentModel = "gpt-4.1-nano"; // TODO: config
    __gptCurrentMessages = [ 
        { 
            "role": "system", 
            "content": `Your task is to generate a confirmation sentence based on the context of the conversation. 

--- 
Examples: 
EXAMPLE DIALOG 1 INPUT: 
Assistant: Hello, how can I help you? 
User: Hi please transfer my call to the agent. 
Example output: Would you like to transfer to an agent? 

EXAMPLE DIALOG 2 INPUT: 
Assistant: What is your name? 
User: My name is John. 
Example output: Do I understand your name is John? 

--- 
Now the real conversation: 

INPUT: 
`+ __gptDialog_getSimplifiedHistory() + ` 

--- 
Now generate a confirmation statement on a single line, don't include role tag. 
Write the output sentence (question) directly without any additional text. Output language must be `+context.language+`
--- 
OUTPUT:` 
        } 
    ] 
}

request = { 
    "model": __gptCurrentModel, 
    "messages": __gptCurrentMessages,
    /*"temperature": parseFloat(__temperature.toString()), */
    "top_p": 1, 
    "service_host": __gptServiceHost, 
    "frequency_penalty": 0,
    "seed": __gptSeed,
    /*"max_tokens": 500,*/
    "presence_penalty": 0 
}
if (__gptModel.indexOf("gpt-5") >= 0) {
    request["max_completion_tokens"] = __gptMaxTokens;
} else {
    request["max_tokens"] = __gptMaxTokens;
    request["temperature"] = parseFloat(__temperature.toString());
}


if (__gptIntents && __confirmIntentMode == 0 && (__sayInstruction == null || __sayInstruction.length == 0)) {
    if (__gptFunctionsDefinition != null && __gptFunctionsDefinition.length == 0) {
        request.functions = null;
    } else {
        request.functions = __gptFunctionsDefinition;
    }
}

__confirmIntentMode = 0; //clear FLAG for confirmation request


__gptFunctionCall = null;

__lastGptRequest = request; 

if (JSON.parse(__logPrompt)) { 
    log_debug("GPT request: "+JSON.stringify(request.messages)); 
} 

__speak = true;
__recognize = true; 

return gptRequest("chat/completions", request).then( 
    function (result) { 
        if (JSON.parse(__logPrompt)) { 
            log_debug("GPT response: " + JSON.stringify(result)); 
        } 

        if (!result || !result.response || !Array.isArray(result.response.choices) || result.response.choices.length == 0) { 
            log_error(JSON.stringify(result)); 

            __gptOutput = "ERROR"; 
        } else { 

            if (result.response.choices && result.response.choices.length > 0 && result.response.choices[0].message.function_call) {

                __gptFunctionCall = result.response.choices[0].message.function_call.name; //.replace("intent_", "");
                __gptFunctionObject = result.response.choices[0].message.function_call;
            } else {
                __gptOutput = result.response.choices[0].message.content; 
            }
        }
    }
);

__gptMarkdownToHTML = function (markdown) { 
    // Replace shortened URLs with full URLs first  
    //markdown = replaceShortenedUrls(markdown);  

    // Replace suggestion links   
    markdown = markdown.replace(/\[(.*?)\]\(#(.*?)\)/g, '<a href="#" class="suggestion-link" data-suggestion="$1">$1</a>'); 

    // Replace image markdown links  
    markdown = markdown.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, function (match, alt, url) { 
        return '<img src="' + url + '" alt="' + alt + '">'; 
    }); 

    // Replace regular markdown links, ignoring those that start with #  
    markdown = markdown.replace(/\[([^\]]+)\]\((?!#)([^)]+)\)/g, function (match, text, url) { 
        // Ensure it's not an image link by checking the absence of '!'  
        if (!match.startsWith('!')) { 
            return '<a href="' + url + '">' + text + '</a>'; 
        } 
        return match; // Return the match as is if it's an image link  
    }); 

    // Replace headings   
    markdown = markdown.replace(/^# (.*)$/gm, '<h1>$1</h1>'); 
    markdown = markdown.replace(/^## (.*)$/gm, '<h2>$1</h2>'); 
    markdown = markdown.replace(/^### (.*)$/gm, '<h3>$1</h3>'); 
    markdown = markdown.replace(/^#### (.*)$/gm, '<h4>$1</h4>'); 
    markdown = markdown.replace(/^##### (.*)$/gm, '<h5>$1</h5>'); 
    markdown = markdown.replace(/^###### (.*)$/gm, '<h6>$1</h6>'); 

    // Replace bold   
    markdown = markdown.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>'); 

    // Replace italic   
    markdown = markdown.replace(/\*(.*?)\*/g, '<em>$1</em>'); 

    // Replace block code syntax   
    markdown = markdown.replace(/```([\s\S]+?)```/g, '<pre class="chat-code-block"><code>$1</code></pre>'); 

    // Replace inline code   
    markdown = markdown.replace(/`([^`]+)`/g, '<code class="chat-inline-code">$1</code>'); 

    // Replace newlines that have two spaces before them with <br>  
    markdown = markdown.replace(/\n\n/g, '<br>'); 

    return markdown; 
} 


// convert last result (output from RAG) to HTML 
__gptLastActionResult = __gptMarkdownToHTML(__gptLastActionResult);

if (__logPrompt) { 
    log_debug('unfinished input/wait request'); 
}

__gptDetectedIntent = null; 

var __regexDigits = /\d.*\d/; 
if (__gptInput && __regexDigits.test(__gptInput)) { 
    __gptDetectedIntent = "user_answered_entity"; // more than one digit is present, always play keyboard sound 
} 


if (__gptIntentClassifier != null && typeof Task !== "undefined") { 

    // wait for short while if there is output from intent classifier available 
    return Task.timeout(100, __gptIntentClassifier, "timeout").then(result => { 
        if (result != "timeout") { 
            if (result.response && 
                result.response.choices && 
                result.response.choices.length > 0 && 
                result.response.choices[0].message && 
                result.response.choices[0].message.content) { 
                var gptDetectedIntent = result.response.choices[0].message.content; 
                __gptDetectedIntent = transformFunctionName(gptDetectedIntent); 
            } 
        } 
    }); 
}
